mapper.select:
SELECT A.CTKEY , COUNT(1) AS TOTALCNT , COUNT(distinct B.ICKEY) AS ICKEYCNT , MAX(B.INSPECTFLAG) AS INSPECTFLAG FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICKEY = C.ICKEY LEFT JOIN TWORK_MST_ICUT D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICUTKEY = D.ICUTKEY LEFT JOIN TWORK_INFO_WA_DT E ON A.CTKEY = E.CTKEY AND A.WAHDKEY = E.WAHDKEY AND A.OBHDKEY = E.OBHDKEY AND A.OWKEY = E.OWKEY LEFT JOIN TWORK_MST_STORE G ON A.CTKEY = G.CTKEY AND A.STORE_KEY = G.STORE_KEY AND A.DCKEY = G.DCKEY LEFT JOIN TWORK_MST_AC H ON C.CTKEY = H.CTKEY AND C.ACKEY = H.ACKEY AND C.OWKEY = H.OWKEY LEFT JOIN TWORK_INFO_LOADPLAN I ON A.CTKEY = I.CTKEY AND A.LOGGRPCD = I.LOGGRPCD AND A.OBHDKEY = I.OBHDKEY LEFT JOIN TWORK_MST_LCXIC J ON C.CTKEY = J.CTKEY AND C.OWKEY = J.OWKEY AND C.ICKEY = J.ICKEY WHERE 1=1 AND A.CTKEY = #{ctkey} AND B.WORKINGYN = 'N' AND D.CLOSDATE >= #{closdate}
AND #{SEARCH_CONDITION}
GROUP BY A.CTKEY

SELECT A.CTKEY , COUNT(1) AS TOTALCNT , COUNT(distinct E.ICKEY) AS ICKEYCNT FROM TWORK_INFO_WA_HD A INNER JOIN TWORK_INFO_WA_DT B ON A.CTKEY = B.CTKEY AND A.WAHDKEY = B.WAHDKEY INNER JOIN TWORK_INFO_OB_HD C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.OBHDKEY = C.OBHDKEY LEFT JOIN TWORK_INFO_WKPRHS D ON C.OBHDKEY = D.SOURCEKEY INNER JOIN TWORK_INFO_PI_DT E ON B.CTKEY = E.CTKEY AND B.OWKEY = E.OWKEY AND B.OBHDKEY = E.OBHDKEY WHERE 1=1 AND A.CTKEY = #{ctkey}
AND A.WAHDKEY IN
#{wahdkeyList}
GROUP BY A.CTKEY

SELECT A.CTKEY , COUNT(1) AS TOTALCNT , COUNT(distinct B.ICKEY) AS ICKEYCNT FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_PI_DT B ON A.CTKEY = B.CTKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.ICKEY = C.ICKEY LEFT JOIN TWORK_MST_ICUT D ON C.OWKEY = D.OWKEY AND C.CTKEY = D.CTKEY AND C.ICUTKEY = D.ICUTKEY LEFT JOIN TWORK_MST_ICUTXTYPE F ON C.OWKEY = F.OWKEY AND C.CTKEY = F.CTKEY AND C.ICUTKEY = F.ICUTKEY AND C.UOM = F.ICUTTYPE LEFT JOIN TWORK_MST_STORE G ON A.CTKEY = G.CTKEY AND A.STORE_KEY = G.STORE_KEY AND A.DCKEY = G.DCKEY WHERE 1=1 AND A.CTKEY = #{ctkey} AND D.CLOSDATE >= #{closdate}
AND #{SEARCH_CONDITION}
GROUP BY A.CTKEY

SELECT A.CTKEY , COUNT(1) AS TOTALCNT , COUNT(distinct C.ICKEY) AS ICKEYCNT FROM TWORK_INFO_WA_HD A ,TWORK_INFO_WA_DT B ,TWORK_INFO_OB_DT C WHERE A.CTKEY = #{ctkey}
AND B.OWKEY = #{owkey}
AND A.CTKEY = B.CTKEY
AND A.WAHDKEY = B.WAHDKEY AND B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.OBHDKEY = C.OBHDKEY AND C.WORKINGYN = 'N' AND C.WKSTATUS >= '00' AND C.WKSTATUS < '81'
AND A.WAHDKEY IN
#{wahdkeyList}
GROUP BY A.CTKEY

SELECT TB1.CTKEY , COUNT(1) AS TOTALCNT , COUNT(distinct TB2.ICKEY) AS ICKEYCNT FROM TWORK_INFO_OB_HD TB1 INNER JOIN TWORK_INFO_OB_DT TB2 ON TB1.CTKEY = TB2.CTKEY AND TB1.OBHDKEY = TB2.OBHDKEY AND TB1.OWKEY = TB2.OWKEY INNER JOIN TWORK_MST_IC TB3 ON TB1.CTKEY = TB3.CTKEY AND TB2.OWKEY = TB3.OWKEY AND TB2.ICKEY = TB3.ICKEY LEFT JOIN TWORK_MST_ICUTXTYPE TB4 ON TB3.OWKEY = TB4.OWKEY AND TB3.CTKEY = TB4.CTKEY AND TB3.ICUTKEY = TB4.ICUTKEY AND TB3.UOM = TB4.ICUTTYPE LEFT JOIN TWORK_INFO_PI_DT TB5 ON TB2.CTKEY = TB5.CTKEY AND TB2.OWKEY = TB5.OWKEY AND TB2.OBHDKEY = TB5.OBHDKEY AND TB2.OBDTKEY = TB5.OBDTKEY INNER JOIN TWORK_MST_STORE TB6 ON TB1.CTKEY = TB6.CTKEY AND TB1.STORE_KEY = TB6.STORE_KEY AND TB1.DCKEY = TB6.DCKEY LEFT JOIN TT_SHPM_LEG_T B1 ON TB1.CTKEY = B1.CTKEY AND TB1.OBHDKEY = B1.SHPMNO AND B1.CUROPTLSTTID >= '204' LEFT JOIN TT_LOAD_T C1 ON B1.LDLEGID = C1.LDLEGID WHERE 1=1 AND TB1.CTKEY = #{ctkey}
AND TB1.OWKEY = #{owkey}
AND TB2.WKSTATUS >= '00' AND TB2.WKSTATUS < '81'
AND #{SEARCH_CONDITION}
GROUP BY TB1.CTKEY

SELECT B.CTKEY ,B.PIDTKEY ,B.EXQTY - B.CFQTY AS QTY ,B.EXQTY ,1 AS ICUTQTY ,B.OBHDKEY ,B.OBDTKEY FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_PI_DT B ON A.CTKEY = B.CTKEY AND A.OBHDKEY = B.OBHDKEY LEFT JOIN TWORK_MST_ICUT C ON B.CTKEY = C.CTKEY AND B.ICUTKEY = C.ICUTKEY LEFT JOIN TWORK_INFO_WA_DT E ON A.CTKEY = E.CTKEY AND A.OWKEY = E.OWKEY AND A.OBHDKEY = E.OBHDKEY INNER JOIN TWORK_MST_IC F ON A.CTKEY = F.CTKEY AND A.OWKEY = F.OWKEY AND B.ICKEY = F.ICKEY LEFT JOIN TWORK_MST_STORE G ON A.CTKEY = G.CTKEY AND A.STORE_KEY = G.STORE_KEY AND A.DCKEY = G.DCKEY LEFT JOIN TWORK_MST_AC I ON A.CTKEY = I.CTKEY AND A.OWKEY = I.OWKEY AND A.ACKEY = I.ACKEY LEFT JOIN TT_SHPM_LEG_T B1 ON A.CTKEY = B1.CTKEY AND A.OBHDKEY = B1.SHPMNO AND B1.CUROPTLSTTID >= '204' LEFT JOIN TT_LOAD_T C1 ON B1.LDLEGID = C1.LDLEGID WHERE 1=1 AND A.CTKEY = #{ctkey} AND C.CLOSDATE >= #{closdate}
AND #{SEARCH_CONDITION}
ORDER BY B.IVATKEY ASC, B.ICKEY ASC

SELECT E.CTKEY ,E.PIDTKEY ,E.EXQTY ,E.WKSTATUS ,E.ICKEY ,C.OBHDTYPE ,E.FR_LCKEY ,E.OBHDKEY ,E.OBDTKEY FROM TWORK_INFO_WA_HD A INNER JOIN TWORK_INFO_WA_DT B ON A.CTKEY = B.CTKEY AND A.WAHDKEY = B.WAHDKEY INNER JOIN TWORK_INFO_OB_HD C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.OBHDKEY = C.OBHDKEY LEFT JOIN TWORK_INFO_WKPRHS D ON C.OBHDKEY = D.SOURCEKEY INNER JOIN TWORK_INFO_PI_DT E ON B.CTKEY = E.CTKEY AND B.OWKEY = E.OWKEY AND B.OBHDKEY = E.OBHDKEY WHERE 1=1 AND A.CTKEY = #{ctkey}
AND A.WAHDKEY IN
#{wahdkeyList}
ORDER BY E.IVATKEY ASC , E.ICKEY ASC

SELECT A.CTKEY ,B.PIDTKEY ,B.EXQTY ,B.WKSTATUS ,B.ICKEY ,A.OBHDTYPE ,B.FR_LCKEY ,B.OBHDKEY ,B.OBDTKEY FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_PI_DT B ON A.CTKEY = B.CTKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.ICKEY = C.ICKEY LEFT JOIN TWORK_MST_ICUT D ON C.OWKEY = D.OWKEY AND C.CTKEY = D.CTKEY AND C.ICUTKEY = D.ICUTKEY LEFT JOIN TWORK_MST_ICUTXTYPE F ON C.OWKEY = F.OWKEY AND C.CTKEY = F.CTKEY AND C.ICUTKEY = F.ICUTKEY AND C.UOM = F.ICUTTYPE LEFT JOIN TWORK_MST_STORE G ON A.CTKEY = G.CTKEY AND A.STORE_KEY = G.STORE_KEY AND A.DCKEY = G.DCKEY WHERE 1=1 AND A.CTKEY = #{ctkey} AND D.CLOSDATE >= #{closdate}
AND #{SEARCH_CONDITION}
ORDER BY B.IVATKEY ASC , B.ICKEY ASC

SELECT E.CTKEY ,E.PIDTKEY ,E.EXQTY ,E.CFQTY AS QTY ,1 AS ICUTQTY ,E.OBHDKEY ,E.OBDTKEY FROM TWORK_INFO_WA_HD A INNER JOIN TWORK_INFO_WA_DT B ON A.CTKEY = B.CTKEY AND A.WAHDKEY = B.WAHDKEY INNER JOIN TWORK_INFO_OB_HD C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.OBHDKEY = C.OBHDKEY LEFT JOIN TWORK_INFO_WKPRHS D ON C.OBHDKEY = D.SOURCEKEY INNER JOIN TWORK_INFO_PI_DT E ON B.CTKEY = E.CTKEY AND B.OWKEY = E.OWKEY AND B.OBHDKEY = E.OBHDKEY WHERE 1=1 AND E.WKSTATUS = '90' AND A.CTKEY = #{ctkey} AND A.WAHDKEY IN
#{wahdkeyList}
ORDER BY E.IVATKEY ASC , E.ICKEY ASC

SELECT B.CTKEY ,B.PIDTKEY ,B.EXQTY / D.ICUTQTY AS EXQTY ,B.CFQTY / D.ICUTQTY AS QTY ,D.ICUTQTY ,B.OBHDKEY ,B.OBDTKEY FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_PI_DT B ON A.CTKEY = B.CTKEY AND A.OBHDKEY = B.OBHDKEY AND A.OWKEY = B.OWKEY LEFT JOIN TWORK_MST_ICUT C ON B.CTKEY = C.CTKEY AND B.ICUTKEY = C.ICUTKEY LEFT JOIN TWORK_MST_ICUTXTYPE D ON B.CTKEY = D.CTKEY AND B.ICUTKEY = D.ICUTKEY AND B.UOM = D.ICUTTYPE LEFT JOIN TWORK_INFO_WA_DT E ON A.CTKEY = E.CTKEY AND A.OWKEY = E.OWKEY AND A.OBHDKEY = E.OBHDKEY INNER JOIN TWORK_MST_IC F ON A.CTKEY = F.CTKEY AND A.OWKEY = F.OWKEY AND B.ICKEY = F.ICKEY LEFT JOIN TWORK_MST_STORE G ON A.CTKEY = G.CTKEY AND A.STORE_KEY = G.STORE_KEY AND A.DCKEY = G.DCKEY LEFT JOIN TWORK_INFO_LOADPLAN H ON A.CTKEY = H.CTKEY AND A.LOGGRPCD = H.LOGGRPCD AND A.OBHDKEY = H.OBHDKEY AND A.STORE_KEY = H.SHPGLOCCD WHERE 1=1 AND A.CTKEY = #{ctkey} AND C.CLOSDATE >= #{closdate}
AND #{SEARCH_CONDITION}
ORDER BY B.IVATKEY ASC , B.ICKEY ASC

SELECT A.CTKEY ,C.OBHDKEY ,C.OBDTKEY ,C.ICKEY FROM TWORK_INFO_WA_HD A ,TWORK_INFO_WA_DT B ,TWORK_INFO_OB_DT C WHERE B.CTKEY = #{ctkey}
AND A.OWKEY = #{owkey}
AND A.CTKEY = B.CTKEY
AND A.WAHDKEY = B.WAHDKEY AND B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.OBHDKEY = C.OBHDKEY AND C.WORKINGYN = 'N' AND C.WKSTATUS >= '00' AND C.WKSTATUS < '81'
AND A.WAHDKEY IN
#{wahdkeyList}
ORDER BY C.ICKEY ASC

SELECT TB1.CTKEY ,TB2.OBHDKEY ,TB2.OBDTKEY ,TB2.ICKEY FROM TWORK_INFO_OB_HD TB1 INNER JOIN TWORK_INFO_OB_DT TB2 ON TB1.CTKEY = TB2.CTKEY AND TB1.OBHDKEY = TB2.OBHDKEY AND TB1.OWKEY = TB2.OWKEY INNER JOIN TWORK_MST_IC TB3 ON TB1.CTKEY = TB3.CTKEY AND TB2.OWKEY = TB3.OWKEY AND TB2.ICKEY = TB3.ICKEY LEFT JOIN TWORK_MST_ICUTXTYPE TB4 ON TB3.OWKEY = TB4.OWKEY AND TB3.CTKEY = TB4.CTKEY AND TB3.ICUTKEY = TB4.ICUTKEY AND TB3.UOM = TB4.ICUTTYPE LEFT JOIN TWORK_INFO_PI_DT TB5 ON TB2.CTKEY = TB5.CTKEY AND TB2.OWKEY = TB5.OWKEY AND TB2.OBHDKEY = TB5.OBHDKEY AND TB2.OBDTKEY = TB5.OBDTKEY INNER JOIN TWORK_MST_STORE TB6 ON TB1.CTKEY = TB6.CTKEY AND TB1.STORE_KEY = TB6.STORE_KEY AND TB1.DCKEY = TB6.DCKEY LEFT JOIN TT_SHPM_LEG_T B1 ON TB1.CTKEY = B1.CTKEY AND TB1.OBHDKEY = B1.SHPMNO AND B1.CUROPTLSTTID >= '204' LEFT JOIN TT_LOAD_T C1 ON B1.LDLEGID = C1.LDLEGID WHERE 1=1 AND TB1.CTKEY = #{ctkey}
AND TB1.OWKEY = #{owkey}
AND TB2.WKSTATUS >= '00' AND TB2.WKSTATUS < '81'
AND #{SEARCH_CONDITION}
ORDER BY TB2.ICKEY

mapper.update:
	UPDATE TWORK_INFO_OB_DT
	   SET WORKINGID = #{workingid}
	      ,UPDATEDATE  = #{sysdate}
          ,UPDATEURKEY = #{surkey}
	 WHERE 
	 	   CTKEY = #{ctkey}
	   AND OBHDKEY = #{obhdkey}
	   AND OBDTKEY = #{obdtkey}

	UPDATE TWORK_TEMP_IVUP
	   SET WORKINGID = #{workingid}
	      ,UPDATEDATE  = #{sysdate}
          ,UPDATEURKEY = #{surkey}
	 WHERE 
	 	   CTKEY = #{ctkey}
	   AND ULHSKEY = #{ulhskey}
